#include <stdio.h>
#include <string.h>
int main(){
    int T;
    if(scanf("%d",&T)!=1) return 0;
    int c=getchar(); // consume newline after T
    char s[105];
    while(T--){
        if(!fgets(s, sizeof s, stdin)) break;
        size_t len=strlen(s);
        if(len && s[len-1]=='\n') s[len-1]='\0';
        putchar(s[7]);
        putchar('\n');
    }
    return 0;
}

